SELECT sentiment, COUNT(*) AS review_count
FROM review_sentiments
GROUP BY sentiment;

SELECT AVG(subjectivity) AS average_subjectivity
FROM review_subjectivities
WHERE review_id = 0;

SELECT review_id, sentiment, confidence, polarity
FROM review_sentiments
WHERE confidence > 0.75;

SELECT COUNT(*) AS base_form_lemmas_count
FROM review_lemmas
WHERE lemma_type = 'base form';

SELECT COUNT(*) 
FROM reviews 
WHERE sentiment = 'positive';
